import React, { useState } from 'react';
import LanguageSwitcher from './LanguageSwitcher';

function Swipe({ 
  user, 
  onProfile, 
  onChat, 
  onFilter, 
  onNotifications, 
  onLogout, 
  onSubscribe, 
  isSubscribed,
  onNearby 
}) {
  const [messagesLeft, setMessagesLeft] = useState(3);
  const [users] = useState([
    { id: 1, name: 'Sarah', age: 24, city: 'Alger', emoji: '👩' },
    { id: 2, name: 'Karim', age: 27, city: 'Oran', emoji: '👨' },
    { id: 3, name: 'Leila', age: 23, city: 'Constantine', emoji: '👩' },
  ]);
  const [index, setIndex] = useState(0);

  const totalMessages = messagesLeft + (user?.extraMessages || 0);

  const next = () => setIndex((i) => (i + 1) % users.length);

  const handleLike = () => {
    if (totalMessages <= 0 && !isSubscribed) {
      return alert('💎 Abonnez-vous ou ajoutez des photos pour plus de messages');
    }
    if (user?.extraMessages > 0) {
      const updatedUser = {
        ...user,
        extraMessages: user.extraMessages - 1
      };
      if (onProfile) onProfile(updatedUser);
    } else {
      setMessagesLeft((m) => m - 1);
    }
    
    alert(`❤️ Vous avez aimé ${users[index].name}`);
    next();
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
          <h1 style={styles.title}>💕 Chatalgerie</h1>
          <LanguageSwitcher />
        </div>
        <div style={styles.headerRight}>
          <button onClick={onNearby} style={styles.iconBtn}>📍</button>
          <button onClick={onFilter} style={styles.iconBtn}>🔍</button>
          <button onClick={onNotifications} style={styles.iconBtn}>🔔</button>
          <button onClick={onChat} style={styles.iconBtn}>💬</button>
          <button onClick={onProfile} style={styles.iconBtn}>👤</button>
          <button onClick={onLogout} style={styles.iconBtn}>🚪</button>
        </div>
      </div>

      <div style={styles.card}>
        <div style={styles.emoji}>{users[index].emoji}</div>
        <h2>{users[index].name}, {users[index].age}</h2>
        <p>📍 {users[index].city}</p>
        
        <div style={styles.messagesInfo}>
          <p style={styles.messagesText}>
            💬 {totalMessages} messages restants
            {user?.extraMessages > 0 && (
              <span style={styles.bonusBadge}> +{user.extraMessages} bonus</span>
            )}
          </p>
          {user?.imageCount > 0 && (
            <p style={styles.photoBadge}>📸 {user.imageCount} photos • {user.imageCount * 5} messages bonus</p>
          )}
        </div>

        <div style={styles.actions}>
          <button onClick={next} style={styles.dislikeBtn}>❌</button>
          <button onClick={handleLike} style={styles.likeBtn}>❤️</button>
        </div>

        {!isSubscribed && (
          <button onClick={onSubscribe} style={styles.premiumBtn}>
            💎 Devenir Premium
          </button>
        )}
        
        {user?.imageCount < 10 && (
          <p style={styles.addPhotoHint}>
            📸 Ajoutez des photos pour +5 messages chacune ({user?.imageCount || 0}/10)
          </p>
        )}
      </div>
    </div>
  );
}

const styles = {
  container: {
    minHeight: '100vh',
    background: 'linear-gradient(135deg, #FFB6C1, #87CEEB)',
    padding: '20px',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
  },
  header: {
    width: '100%',
    maxWidth: '400px',
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    marginBottom: '10px',
  },
  headerRight: {
    display: 'flex',
    gap: '6px',
    flexWrap: 'wrap',
    justifyContent: 'flex-end',
  },
  iconBtn: {
    background: 'rgba(255,255,255,0.8)',
    border: 'none',
    borderRadius: '50%',
    width: '36px',
    height: '36px',
    fontSize: '0.9rem',
    cursor: 'pointer',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
  },
  title: {
    background: 'linear-gradient(45deg, #FF69B4, #4A90D9)',
    WebkitBackgroundClip: 'text',
    WebkitTextFillColor: 'transparent',
    fontSize: '1.5rem',
    margin: 0,
  },
  card: {
    backgroundColor: 'white',
    padding: '30px',
    borderRadius: '24px',
    maxWidth: '400px',
    width: '100%',
    textAlign: 'center',
    marginTop: '10px',
  },
  emoji: {
    fontSize: '80px',
  },
  messagesInfo: {
    marginTop: '15px',
    padding: '12px',
    backgroundColor: '#f8f9fa',
    borderRadius: '12px',
  },
  messagesText: {
    margin: 0,
    fontSize: '1.1rem',
    fontWeight: 'bold',
    color: '#333',
  },
  bonusBadge: {
    color: '#4CAF50',
    fontSize: '0.9rem',
    marginLeft: '5px',
  },
  photoBadge: {
    margin: '5px 0 0 0',
    fontSize: '0.85rem',
    color: '#888',
  },
  addPhotoHint: {
    marginTop: '10px',
    fontSize: '0.8rem',
    color: '#4A90D9',
    cursor: 'pointer',
  },
  actions: {
    display: 'flex',
    justifyContent: 'center',
    gap: '30px',
    marginTop: '20px',
  },
  dislikeBtn: {
    background: '#FF6B6B',
    border: 'none',
    fontSize: '30px',
    borderRadius: '50%',
    width: '60px',
    height: '60px',
    cursor: 'pointer',
  },
  likeBtn: {
    background: '#FF1493',
    border: 'none',
    fontSize: '30px',
    borderRadius: '50%',
    width: '60px',
    height: '60px',
    cursor: 'pointer',
  },
  premiumBtn: {
    marginTop: '20px',
    background: '#FFD700',
    padding: '12px 20px',
    borderRadius: '12px',
    border: 'none',
    fontWeight: 'bold',
    cursor: 'pointer',
    fontSize: '1rem',
  },
};

export default Swipe;
